var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"LOBBYIST_NPC_NULL_NULL","text":{"KOREA":"어떠십니까!","JPN":"いかがですか！","ENG":"What do you think, ma'am?","TWN":"怎麼樣！"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LOBBYIST_NPC_NULL_NULL","text":{"KOREA":"이 신무기라면 제 3종 침식체도 한 방에 쓰러트릴 수 있지요!","JPN":"この新武器なら第3種侵食体も一発で倒せますよ！","ENG":"This new weapon can take down a Category 3 with a single blow!","TWN":"用這個新武器的話，一擊就能打倒3級侵蝕體！"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LOBBYIST_NPC_NULL_NULL","text":{"KOREA":"저희 알파트릭스 헤비 암즈의 최첨단 기술과 노하우가 집약된 걸작입니다!","JPN":"私たちアルファトリックス・ヘビーアームズの最先端技術とノウハウが集約された傑作なんです！","ENG":"This is a masterpiece combining the most cutting edge technology and knowhow of Alphatrix Heavy Arms!","TWN":"它結合了我們阿爾法崔克斯重武器最尖端的技術和秘密科技，毫無疑問是個傑作！"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"정말인가?","JPN":"本当か？","ENG":"Really?","TWN":"真的嗎？"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"마침 다음 작전에서 제 3종 침식체가 나올 확률이 높다던데, 바로 시험해 봐도 되겠지?","JPN":"ちょうど次の作戦で第3種侵食体が出る確率が高いらしいが、その時に試してみてもいいか？","ENG":"Then I suppose we can test it right away in our next operation? There's a high probability we'll encounter a Category 3.","TWN":"正好下次作戰時3級侵蝕體出現的機率很高，到時候我們就能試驗一下了。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LOBBYIST_NPC_NULL_NULL","text":{"KOREA":"아, 아니 그게......","JPN":"い、いや、それが……","ENG":"W-well, you see...","TWN":"啊，不是，那個……"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LOBBYIST_NPC_NULL_NULL","text":{"KOREA":"사실 꼭 한 방에 쓰러트린다는 뜻은 아니고요......","JPN":"実は、必ず一発で倒せるわけではなくて……","ENG":"I didn't mean it'll literally take them down in a single blow...","TWN":"也不是說一定就能一擊必殺……"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LOBBYIST_NPC_NULL_NULL","text":{"KOREA":"아마도 두 방...... 어쩌면 세 방 정도에는 확실하게......","JPN":"多分二発……もしかしたら三発くらいなら確実に……","ENG":"Maybe more like two blows? Three blows, definitely, I think...","TWN":"估計是兩下…….也有可能是三下……"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그거 유감이군.","JPN":"それは残念だ。","ENG":"That's a shame.","TWN":"那可真是遺憾。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"제 3종 침식체가 가만히 앉아서 세 방이나 맞아주고 있을 것 같지는 않아서 말이야.","JPN":"第3種侵食体が三発も撃たれるまで、じっとしてくれるとは思えないがな。","ENG":"I don't think a Category 3 will wait around until we can land three shots on it.","TWN":"3級侵蝕體應該不會乖乖坐著讓我打它三下吧。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LOBBYIST_NPC_NULL_NULL","text":{"KOREA":"아! 그런 거라면 걱정 마십시오!","JPN":"あ！　そのことならご安心を！","ENG":"Oh! If that's what you're worried about, don't you worry, ma'am!","TWN":"啊！這一點您不用擔心了！"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LOBBYIST_NPC_NULL_NULL","text":{"KOREA":"이 카탈로그를 보시면 신무기에 장착 가능한 저희의 새로운 능동 유도 장치 옵션이 있습니다!","JPN":"このカタログをご覧ください。新武器に装着可能な新しい能動誘導装置オプションがあります！","ENG":"As you'll note in the catalog, the new weapon is compatible with our latest active guidance system!","TWN":"請看這邊的目錄，這裡有新的主動誘導外掛程式，可以裝備在新武器上！"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LOBBYIST_NPC_NULL_NULL","text":{"KOREA":"이 장치를 구매하시면 어떤 침식체도 신무기의 공격을 피할 수 없지요!","JPN":"この装置を購入していただくと、いかなる侵食体も新武器の攻撃を避けられません！","ENG":"With this device, no C.O. will be able to dodge this new weapon!","TWN":"只要購買並裝備此外掛程式，任何侵蝕體都將無法躲避您的攻擊！"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"아, 지난 번 실전 테스트에서 명중률이 30%도 안 나왔던 그 유도 장치 말이군.","JPN":"ほお、先日の実戦テストで命中率が30％しか出なかったあの誘導装置のことか。","ENG":"Oh, you mean the guidance system that had an accuracy of less than 30% in the field test last time.","TWN":"啊，是上次那個實戰命中率不到30%的誘導外掛程式啊。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"아주 인상적이었네.","JPN":"とても印象的だったよ。","ENG":"That was most impressive.","TWN":"十分令人印象深刻呢。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LOBBYIST_NPC_NULL_NULL","text":{"KOREA":"그, 그건 테스트 환경의 침식파가 상정했던 것보다 너무 강해서 어쩔 수 없이......","JPN":"そ、それはテスト環境の侵食波が想定より強すぎてどうしようもなく……","ENG":"T-that was because the Corruption Ray in the testing environment was a lot higher than we had calibrated for...","TWN":"那，那是因為當時測試環境的侵蝕波比預想的還要強……"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"아아, 그랬었군. 충분히 이해하네.","JPN":"ああ、なるほどな。十分理解している。","ENG":"Oh, right. Of course. I understand.","TWN":"啊，原來是這樣啊，我明白了。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"나도 귀사의 놀라운 신무기를 도입하고 싶은 마음이 간절하네.","JPN":"私も御社の見事な新武器を導入したいと考えている。","ENG":"I'd love to acquire your company's amazing new weapons as well.","TWN":"我也很想引進貴公司驚人的新式武器。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"하지만 아무리 그래도 이런 일을 내 마음대로 결정할 수는 없는 법이지.","JPN":"だが、いくらなんでもこんなことを独断で決めるわけにはいかないからな。","ENG":"However, this isn't something I can just decide on my own.","TWN":"但這種事不是我能隨便決定的。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};